"""Full cross-page section content similarity analysis for Nexa Paraguay."""
import json, os

pages_dir = "/root/nexa-paraguay/nexa-pages"
content_file = "/root/nexa-paraguay/content/en.json"

with open(content_file) as f:
    content = json.load(f)

SECTION_COMPONENTS = {
    "hero": "HeroSection", "stats-counter": "StatsSection", "trust-signals": "TrustSection",
    "programs-comparison": "ProgramsSection", "services": "ServicesSection",
    "tax-savings-calculator": "TaxCalculatorSection", "why-destination": "WhyCountrySection",
    "features": "FeaturesSection", "process-timeline": "ProcessSection",
    "testimonials": "TestimonialsSection", "cta-banner": "CtaBanner",
    "faq": "FaqSearchSection", "blog-index": "BlogSection", "team": "TeamSection",
    "privacy-accordion": "PrivacyAccordion", "glossary": "GlossarySection",
    "newsletter-signup": "NewsletterSection", "story": "StorySection", "pillars": "PillarsSection",
    "page-hero": "PageHeroSection", "highlights": "HighlightSection",
    "comparison-table": "ComparisonSection", "guides": "GuidesSection",
    "booking-embed": "BookingEmbedSection", "contact": "ContactDetailsSection",
    "gallery": "GallerySection", "faq-search": "FaqSearchSection",
    "contact-form": "ContactFormSection", "services-detail": "ServiceDetailSection",
    "press-releases": "PressReleasesListSection", "intake-wizard": "IntakeWizardSection",
    "whatsapp-float": "WhatsAppFloat", "process-teaser": "GenericFallback",
}

def resolve(obj, path):
    parts = path.split(".")
    v = obj
    for p in parts:
        if isinstance(v, dict):
            v = v.get(p, {})
        else:
            return {}
    return v

def content_signature(obj):
    """Create a compact structural signature for comparison."""
    if isinstance(obj, dict):
        keys = sorted(obj.keys())
        # Skip keys that are always different (seo, cta hrefs, etc.)
        sig_keys = [k for k in keys if k not in ("seo", "ctaHref", "image", "imageUrl", "icon")]
        items = []
        for k in sig_keys:
            v = obj[k]
            if isinstance(v, (list, dict)):
                items.append((k, content_signature(v)))
            else:
                items.append((k, str(v)[:60]))
        return tuple(items)
    elif isinstance(obj, list):
        if not obj:
            ()
        # Compare first item's structure
        return tuple(content_signature(o) for o in obj[:3])
    return str(obj)[:60]

all_pages = {}
for fname in sorted(os.listdir(pages_dir)):
    if not fname.endswith(".json"):
        continue
    page_id = fname.replace(".json", "")
    with open(os.path.join(pages_dir, fname)) as f:
        all_pages[page_id] = json.load(f)

# For each page, collect rendered sections with their content signatures
page_sections = {}
for page_id, config in all_pages.items():
    sections = []
    for sec in config.get("sections", []):
        sec_id = sec.get("id")
        content_path = sec.get("content", "")
        component = SECTION_COMPONENTS.get(sec_id, "GenericFallback")

        # Resolve the content
        data = resolve(content, content_path) if content_path else {}

        sections.append({
            "id": sec_id,
            "component": component,
            "content_path": content_path,
            "data": data,
            "sig": content_signature(data)
        })
    page_sections[page_id] = sections

# Find same-component sections with similar content signatures
# Group by component name, then compare content paths
component_groups = {}
for page_id, sections in page_sections.items():
    for sec in sections:
        comp = sec["component"]
        if comp not in component_groups:
            component_groups[comp] = []
        component_groups[comp].append({
            "page": page_id,
            "id": sec["id"],
            "path": sec["content_path"],
            "sig": sec["sig"]
        })

print("=== DUPLICATE SECTION ANALYSIS ===\n")
print("Look for: same component, same structural content, different pages\n")

for comp, instances in sorted(component_groups.items()):
    if len(instances) < 2:
        continue

    # Compare signatures
    seen = {}
    for inst in instances:
        sig = inst["sig"]
        page_id = inst["page"]
        sec_id = inst["id"]
        cpath = inst["path"]

        if sig not in seen:
            seen[sig] = []
        seen[sig].append(f"  {page_id:20s}  {sec_id:20s}  {cpath}")

    for sig, entries in seen.items():
        if len(entries) >= 2:
            print(f"\n{comp} — IDENTICAL CONTENT across {len(entries)} pages:")
            for e in entries:
                print(e)
            print()

print("\n=== DETAILED COMPARISON: programs-comparison ===")
# Now let's look at actual content not just signature
for page_id in ["home", "programas", "empresa", "inversor", "lifestyle", "trust"]:
    if page_id not in all_pages:
        continue
    config = all_pages[page_id]
    for sec in config.get("sections", []):
        if sec.get("id") in ("programs-comparison",):
            cpath = sec.get("content", "")
            data = resolve(content, cpath)
            tiers = data.get("tiers", data.get("programs", {}).get("tiers", []))
            if not tiers:
                # Maybe it's nested differently
                data2 = resolve(content, cpath.split(".")[0]) if "." in cpath else {}
                tiers = data2.get("tiers", [])
            names = [t.get("name", "") for t in (tiers if isinstance(tiers, list) else [])]
            prices = [t.get("price", "") for t in (tiers if isinstance(tiers, list) else [])]
            print(f"  {page_id:12s}  {cpath:35s}  tiers={names} prices={prices}")

print("\n\n=== DETAILED COMPARISON: cta-banner ===")
for page_id in sorted(all_pages.keys()):
    config = all_pages[page_id]
    for sec in config.get("sections", []):
        if sec.get("id") == "cta-banner":
            cpath = sec.get("content", "")
            data = resolve(content, cpath)
            print(f"  {page_id:15s}  title='{data.get('title','')}'  subtitle='{data.get('subtitle','')}'  btn='{data.get('buttonText','') or data.get('ctaText','')}'")

print("\n\n=== DETAILED COMPARISON: trust-signals ===")
for page_id in sorted(all_pages.keys()):
    config = all_pages[page_id]
    for sec in config.get("sections", []):
        if sec.get("id") == "trust-signals":
            cpath = sec.get("content", "")
            data = resolve(content, cpath)
            items = data.get("items", [])
            titles = [i.get("title","") for i in items]
            print(f"  {page_id:15s}  {cpath:35s}  {titles}")

print("\n\n=== DETAILED COMPARISON: testimonials ===")
for page_id in sorted(all_pages.keys()):
    config = all_pages[page_id]
    for sec in config.get("sections", []):
        if sec.get("id") == "testimonials":
            cpath = sec.get("content", "")
            data = resolve(content, cpath)
            items = data.get("items", [])
            names = [i.get("name","") or i.get("author","") for i in items]
            print(f"  {page_id:15s}  {cpath:35s}  items={len(items)}  {names[:3]}")

print("\n\n=== DETAILED COMPARISON: why-destination ===")
for page_id in sorted(all_pages.keys()):
    config = all_pages[page_id]
    for sec in config.get("sections", []):
        if sec.get("id") == "why-destination":
            cpath = sec.get("content", "")
            data = resolve(content, cpath)
            items = data.get("items",[]) or data.get("pillars",[])
            titles = [i.get("title","") for i in items]
            print(f"  {page_id:15s}  {cpath:35s}  {titles}")

print("\n\n=== ALL FAQ sections comparison ===")
for page_id in sorted(all_pages.keys()):
    config = all_pages[page_id]
    for sec in config.get("sections", []):
        if sec.get("id") in ("faq", "faq-search"):
            cpath = sec.get("content", "")
            data = resolve(content, cpath)
            items = data.get("items",[]) or data.get("full",{}).get("items",[])
            first_q = items[0].get("q","")[:50] if items else "(empty)"
            print(f"  {page_id:15s}  {cpath:35s}  {len(items)} items  first: {first_q}")
